/**
 * Sign in as an existing variant's Auth0 user, hit /api/documents to list
 * generated documents, then download every DOCX via the presigned URL
 * returned by /api/documents/[id]/download.
 *
 * Used to retrieve the bytes generated by e2e-5-variants-postfix.mjs so we
 * can convert to PDF and read each page for visual QA. Dashboard listing
 * a document does NOT count as verification.
 *
 * USAGE
 *   node scripts/download-variant-docs.mjs 1            # variant 1
 *   node scripts/download-variant-docs.mjs 1 2 3 4 5    # all five
 */
import { chromium } from 'playwright';
import { join } from 'path';
import { mkdirSync, writeFileSync } from 'fs';

const URL = process.env.E2E_URL || 'https://company-formation-questio-git-ef61b9-avenidalegal2025s-projects.vercel.app';
const DIR = join(process.env.USERPROFILE || '.', 'Downloads', 'e2e-5-variants-postfix');
mkdirSync(DIR, { recursive: true });
const PASSWORD = 'PostfixSmoke2026!';

function emailFor(id) { return `trimaran.llc+pfx${id}@gmail.com`; }

async function downloadFor(id) {
  const email = emailFor(id);
  console.log(`\n--- variant ${id}: ${email} ---`);

  const browser = await chromium.launch({ headless: true });
  const ctx = await browser.newContext({ viewport: { width: 1400, height: 900 } });
  const page = await ctx.newPage();
  page.setDefaultTimeout(30000);

  try {
    // Sign in
    await page.goto(URL + '/api/auth/signin', { waitUntil: 'networkidle' }).catch(() => {});
    await page.waitForTimeout(2000);
    // The signin page may redirect through Auth0
    if (page.url().includes('auth0') || page.url().includes('/login')) {
      await page.fill('input[name="email"]', email);
      await page.fill('input[name="password"]', PASSWORD);
      await page.click('button:has-text("Continue"), button[type="submit"]');
      await page.waitForTimeout(6000);
      if (await page.locator('button:has-text("Accept")').isVisible().catch(() => false)) {
        await page.click('button:has-text("Accept")');
      }
      await page.waitForTimeout(4000);
    } else {
      // Maybe there's a Sign in button on the page
      const signin = page.locator('a:has-text("Sign in"), button:has-text("Sign in"), a:has-text("Iniciar")').first();
      if (await signin.isVisible().catch(() => false)) {
        await signin.click();
        await page.waitForTimeout(3000);
        await page.fill('input[name="email"]', email);
        await page.fill('input[name="password"]', PASSWORD);
        await page.click('button:has-text("Continue"), button[type="submit"]');
        await page.waitForTimeout(6000);
      }
    }

    // Go to documents
    await page.goto(URL + '/client/documents', { waitUntil: 'networkidle' }).catch(() => {});
    await page.waitForTimeout(4000);

    // Fetch document list via the API the page uses
    const docs = await page.evaluate(async () => {
      const r = await fetch('/api/documents', { credentials: 'include' });
      if (!r.ok) return { error: r.status };
      const j = await r.json();
      return j;
    });
    console.log(`  /api/documents → ${docs.documents ? `${docs.documents.length} docs` : JSON.stringify(docs).slice(0, 200)}`);

    if (!docs.documents) {
      // Try alternate: read from DOM
      const fromDom = await page.evaluate(() => {
        const items = [];
        document.querySelectorAll('a[href*="/api/documents/"], button[data-doc-id], [data-document-id]').forEach(el => {
          items.push({ id: el.getAttribute('data-doc-id') || el.getAttribute('data-document-id') || el.getAttribute('href'), text: el.innerText });
        });
        return items;
      });
      console.log(`  DOM doc handles: ${fromDom.length}`);
      for (const d of fromDom) console.log(`    ${JSON.stringify(d).slice(0, 200)}`);
      await page.screenshot({ path: join(DIR, `v${id}_documents_signedin.png`), fullPage: true });
      await browser.close();
      return;
    }

    // Download each
    for (const d of docs.documents) {
      const downloadResp = await page.evaluate(async (docId) => {
        const r = await fetch(`/api/documents/${docId}/download`, { credentials: 'include' });
        return { status: r.status, body: await r.json().catch(() => ({})) };
      }, d.id);

      if (downloadResp.status !== 200 || !downloadResp.body?.url) {
        console.log(`  ✗ ${d.name}: ${downloadResp.status} ${JSON.stringify(downloadResp.body).slice(0, 120)}`);
        continue;
      }
      const presigned = downloadResp.body.url;
      const blob = await page.evaluate(async (u) => {
        const r = await fetch(u);
        const buf = await r.arrayBuffer();
        return Array.from(new Uint8Array(buf));
      }, presigned);
      const safeName = (d.name || d.id).replace(/[^A-Za-z0-9._-]/g, '_').slice(0, 80);
      const outPath = join(DIR, `v${id}_${safeName}.docx`);
      writeFileSync(outPath, Buffer.from(blob));
      console.log(`  ✓ ${d.name} → ${outPath} (${blob.length} bytes)`);
    }
  } catch (e) {
    console.log(`  ERROR: ${e.message}`);
    await page.screenshot({ path: join(DIR, `v${id}_download_error.png`), fullPage: true }).catch(() => {});
  }

  await browser.close();
}

async function main() {
  const ids = process.argv.slice(2).map(Number).filter(n => n >= 1 && n <= 5);
  if (ids.length === 0) { console.error('Pass variant IDs e.g. `node scripts/download-variant-docs.mjs 1 2`'); process.exit(1); }
  for (const id of ids) await downloadFor(id);
}
main().catch(e => { console.error('FATAL:', e); process.exit(2); });
